 47→    }
 48→
 49→    const parsedCanvasDoc = typeof canvasDoc === 'string' ? JSON.parse(canvasDoc) : canvasDoc;
 50→    if(!parsedCanvasDoc || typeof parsedCanvasDoc !== 'object'){
 51→        throw new Error('canvas_doc should be a valid object');
 52→    }
 53→
 54→    if(!Array.isArray(parsedCanvasDoc.snippets)){
 55→        throw new Error('canvas_doc.snippets should be an array');
