391→export const updateJournalService = async(content, title, journalId, userId, postType = null, canvasDocInput = null) => {
392→    if(!journalId){
393→        console.error('journalid is undefined');
394→        throw {status: 400, error: 'journalId is undefined'}
395→    }
396→
397→    if(!userId){
398→        console.error('userId is undefined')
399→        throw({status: 400, error: 'userId is undefined'})
400→    }
401→
402→    const resolvedRequestedPostType = postType ? normalizePostType(postType) : null;
403→
404→    const {data: existingJournal, error: existingJournalError} = await supabase
405→    .from('journals')
406→    .select('id, user_id, content, title, post_type, canvas_doc')
407→    .eq('id', journalId)
408→    .eq('user_id', userId)
409→    .maybeSingle();
410→
411→    if(existingJournalError){
412→        console.error('failed to fetch existing journal for update', existingJournalError.message);
413→        throw {status: 500, error: 'failed to fetch existing journal for update'};
414→    }
415→
416→    if(!existingJournal){
417→        console.error('journal not found for update');
418→        throw {status: 404, error: 'journal not found for update'};
419→    }
420→
421→    const resolvedPostType = resolvedRequestedPostType || normalizePostType(existingJournal.post_type);
422→    const resolvedTitle = typeof title === 'string' && title.trim() ? title.trim() : existingJournal.title;
423→    if(!resolvedTitle){
424→        console.error('title is undefined');
425→        throw {status: 400, error: 'title is undefined'};
426→    }
427→
428→    let resolvedContent = existingJournal.content;
429→    let resolvedCanvasDoc = existingJournal.canvas_doc;
430→    let embeddingBody = '';
431→
432→    if(resolvedPostType === POST_TYPE_CANVAS){
433→        if(canvasDocInput){
434→            try {
435→                resolvedCanvasDoc = parseCanvasDocInput(canvasDocInput);
436→            } catch (error) {
437→                console.error('invalid canvas doc on update:', error?.message || error);
438→                throw {status: 400, error: 'invalid canvas_doc'};
439→            }
440→        }
441→
442→        if(!resolvedCanvasDoc){
443→            console.error('canvas_doc is missing for canvas post update');
444→            throw {status: 400, error: 'canvas_doc is missing for canvas post update'};
445→        }
446→
447→        resolvedContent = null;
448→        embeddingBody = extractCanvasPlainText(resolvedCanvasDoc);
449→    } else {
450→        if(typeof content === 'string' && content.trim()){
451→            resolvedContent = content;
452→        }
453→
454→        if(!resolvedContent){
455→            console.error('text content is missing for text post update');
456→            throw {status: 400, error: 'text content is missing for text post update'};
457→        }
458→
459→        const parseData = parseTextContentSafely(resolvedContent);
460→        if(!parseData){
461→            console.error('failed to parse text content for update');
462→            throw {status: 400, error: 'failed to parse text content for update'};
463→        }
464→
465→        resolvedCanvasDoc = null;
466→        embeddingBody = parseData.wholeText || '';
467→    }
468→
469→    const embeddings = await GenerateEmbeddings(resolvedTitle, embeddingBody);
470→
471→    const embeddingResult = embeddings;
472→    if(!embeddingResult || !Array.isArray(embeddingResult) || embeddingResult.length === 0){
473→        console.error('failed to generate embeddings')
474→        throw {status: 400, error: 'failed to generate embeddings'};
475→    }
476→
477→    const journalData = {
478→        content: resolvedContent,
479→        title: resolvedTitle,
480→        post_type: resolvedPostType,
481→        canvas_doc: resolvedCanvasDoc,
482→        embeddings: embeddings
483→    }
484→
485→    const {data, error} = await supabase
486→    .from('journals')
487→    .update(journalData)
488→    .eq('id', journalId)
489→    .eq('user_id', userId)
490→
491→    if(error){
492→        console.error('supabase error while uploading content:', error.message);
493→        throw{status: 500, error: 'supabase error while uploading content'};
494→    }
495→
496→    return true;
497→}
