 10→const ProfileMediaSection = () => {
 11→    const { user, session } = useAuth();
 12→    const queryClient = useQueryClient();
 13→    const userId = user?.userData?.[0]?.id;
 14→    const [selectedMedia, setSelectedMedia] = useState(null);
 15→    const [activeMenuId, setActiveMenuId] = useState(null);
 16→    const [deleteCandidate, setDeleteCandidate] = useState(null);
 17→    const { ref: inViewRef, inView } = useInView({ threshold: 0.1 });
 18→
 19→    const { data, isLoading, isError, fetchNextPage, hasNextPage, isFetchingNextPage } = useInfiniteQuery({
 20→        queryKey: ["profileMedia", userId],
 21→        queryFn: ({ pageParam }) => getProfileMedia(session?.access_token, pageParam, PROFILE_MEDIA_PAGE_SIZE),
 22→        initialPageParam: null,
 23→        getNextPageParam: (lastPage) => (lastPage?.hasMore ? lastPage?.nextCursor : undefined),
 24→        enabled: Boolean(userId && session?.access_token),
 25→        refetchOnWindowFocus: false,
 26→    });
 27→
 28→    const pages = data?.pages ?? [];
 29→    const mediaItems = pages.flatMap((page) => page?.data ?? []);
 30→    const unavailableBuckets = [...new Set(pages.flatMap((page) => page?.unavailableBuckets ?? []))];
 31→    const hasMedia = mediaItems.length > 0;
 32→
 33→    const deleteMediaMutation = useMutation({
 34→        mutationFn: (targetMedia) =>
 35→            deleteProfileMediaImage(session?.access_token, {
 36→                bucket: targetMedia.bucket,
 37→                path: targetMedia.path,
 38→                url: targetMedia.url,
 39→            }),
 40→        onSuccess: (response, targetMedia) => {
 41→            setDeleteCandidate(null);
 42→            setActiveMenuId(null);
 43→
 44→            if (selectedMedia?.id === targetMedia?.id) {
 45→                setSelectedMedia(null);
 46→            }
 47→
 48→            queryClient.setQueryData(["profileMedia", userId], (oldData) => {
 49→                if (!oldData || !Array.isArray(oldData.pages)) {
 50→                    return oldData;
 51→                }
 52→
 53→                return {
 54→                    ...oldData,
 55→                    pages: oldData.pages.map((page) => ({
 56→                        ...page,
 57→                        data: Array.isArray(page?.data) ? page.data.filter((item) => item.id !== targetMedia.id) : page?.data,
 58→                    })),
 59→                };
 60→            });
 61→
 62→            queryClient.invalidateQueries({ queryKey: ["profileMedia", userId] });
 63→
 64→            if (response?.clearedAvatar || response?.clearedBackground) {
 65→                queryClient.invalidateQueries({ queryKey: ["userData"] });
 66→            }
 67→        },
 68→    });
 69→
 70→    const handleOpenMedia = (item) => {
 71→        if (!item?.url) return;
 72→        setSelectedMedia(item);
 73→    };
 74→
 75→    const handleToggleSettingsMenu = (event, mediaId) => {
 76→        event.stopPropagation();
 77→        setActiveMenuId((currentId) => (currentId === mediaId ? null : mediaId));
 78→    };
 79→
 80→    const handleOpenDeleteModal = (event, item) => {
 81→        event.stopPropagation();
 82→        setDeleteCandidate(item);
 83→        setActiveMenuId(null);
 84→    };
 85→
 86→    const handleCloseDeleteModal = () => {
 87→        setDeleteCandidate(null);
 88→    };
 89→
 90→    const handleConfirmDelete = () => {
 91→        if (!deleteCandidate || deleteMediaMutation.isPending) {
 92→            return;
 93→        }
 94→
 95→        deleteMediaMutation.mutate(deleteCandidate);
 96→    };
 97→
 98→    const handleCloseMedia = () => {
 99→        setSelectedMedia(null);
100→    };
101→
102→    const profileParentContainer = typeof document !== "undefined" ? document.querySelector(".profile-parent-container") : null;
103→
104→    useEffect(() => {
105→        if (inView && hasNextPage && !isFetchingNextPage) {
106→            fetchNextPage();
107→        }
108→    }, [inView, hasNextPage, isFetchingNextPage, fetchNextPage]);
109→
110→    useEffect(() => {
111→        const handleWindowClick = (event) => {
112→            if (!event.target.closest(".profile-media-item-actions")) {
113→                setActiveMenuId(null);
114→            }
115→        };
116→
117→        window.addEventListener("click", handleWindowClick);
118→        return () => window.removeEventListener("click", handleWindowClick);
119→    }, []);
120→
121→    useEffect(() => {
122→        if (!selectedMedia && !deleteCandidate) return;
123→
124→        const handleEscape = (event) => {
125→            if (event.key === "Escape") {
126→                if (deleteCandidate) {
127→                    handleCloseDeleteModal();
128→                    return;
129→                }
130→
131→                handleCloseMedia();
132→            }
133→        };
134→
135→        window.addEventListener("keydown", handleEscape);
136→        return () => window.removeEventListener("keydown", handleEscape);
137→    }, [selectedMedia, deleteCandidate]);
138→
139→    return (
140→        <section className="profile-media-section" aria-label="Profile media">
141→            <div className="profile-media-header-row">
142→                <h2 className="profile-media-heading">
143→                    Posts <span className="profile-media-count">({mediaItems.length})</span>
144→                </h2>
145→            </div>
146→
147→            {unavailableBuckets.length > 0 && <p className="profile-media-warning">Unable to list: {unavailableBuckets.join(", ")}.</p>}
148→
149→            {isLoading && (
150→                <div className="profile-media-grid">
151→                    {Array.from({ length: 9 }).map((_, index) => (
152→                        <div key={`media-loading-${index}`} className="profile-media-grid-item profile-media-grid-loading-item" />
153→                    ))}
154→                </div>
155→            )}
156→
157→            {!isLoading && isError && <p className="profile-media-empty-state">Unable to load your media right now.</p>}
158→
159→            {!isLoading && !isError && !hasMedia && <p className="profile-media-empty-state">No media found in your buckets yet.</p>}
160→
161→            {!isLoading && !isError && hasMedia && (
162→                <div className="profile-media-grid">
163→                    {mediaItems.map((item) => (
164→                        <div key={item.id} className="profile-media-grid-item">
165→                            <button
166→                                className="profile-media-grid-image-button"
167→                                type="button"
168→                                onClick={() => handleOpenMedia(item)}
169→                                title={`View ${item.bucket} image full size`}
170→                            >
171→                                <img className="profile-media-image" src={item.url} alt={`${item.bucket} media`} loading="lazy" />
172→                            </button>
173→                            <div className="profile-media-item-actions">
174→                                <button
175→                                    className="profile-media-item-settings-btn"
176→                                    type="button"
177→                                    onClick={(event) => handleToggleSettingsMenu(event, item.id)}
178→                                    aria-label="Open image settings"
179→                                >
180→                                    <svg xmlns="http://www.w3.org/2000/svg" height="18" viewBox="0 -960 960 960" width="18" fill="currentColor">
181→                                        <path d="M240-400q-33 0-56.5-23.5T160-480q0-33 23.5-56.5T240-560q33 0 56.5 23.5T320-480q0 33-23.5 56.5T240-400Zm240 0q-33 0-56.5-23.5T400-480q0-33 23.5-56.5T480-560q33 0 56.5 23.5T560-480q0 33-23.5 56.5T480-400Zm240 0q-33 0-56.5-23.5T640-480q0-33 23.5-56.5T720-560q33 0 56.5 23.5T800-480q0 33-23.5 56.5T720-400Z" />
182→                                    </svg>
183→                                </button>
184→                                {activeMenuId === item.id && (
185→                                    <div className="profile-media-item-settings-menu" role="menu" aria-label="Image actions">
186→                                        <button className="profile-media-item-delete-btn" type="button" onClick={(event) => handleOpenDeleteModal(event, item)}>
187→                                            Delete image
188→                                        </button>
189→                                    </div>
190→                                )}
191→                            </div>
192→                        </div>
193→                    ))}
194→                    {isFetchingNextPage &&
195→                        Array.from({ length: PROFILE_MEDIA_PAGE_SIZE }).map((_, index) => (
196→                            <div key={`media-loading-next-${index}`} className="profile-media-grid-item profile-media-grid-loading-item" />
197→                        ))}
198→                </div>
199→            )}
200→
201→            {!isLoading && hasMedia && hasNextPage && <div ref={inViewRef} className="profile-media-infinite-sentinel" />}
202→
203→            {selectedMedia &&
204→                profileParentContainer &&
205→                createPortal(
206→                <div className="profile-media-lightbox-overlay" onClick={handleCloseMedia} role="presentation">
207→                    <div className="profile-media-lightbox-dialog" role="dialog" aria-modal="true" aria-label="Full size media preview" onClick={(event) => event.stopPropagation()}>
208→                        <button className="profile-media-lightbox-close" type="button" onClick={handleCloseMedia} aria-label="Close image preview">
209→                            <svg xmlns="http://www.w3.org/2000/svg" height="22" viewBox="0 -960 960 960" width="22" fill="currentColor">
210→                                <path d="m291-240-51-51 189-189-189-189 51-51 189 189 189-189 51 51-189 189 189 189-51 51-189-189-189 189Z" />
211→                            </svg>
212→                        </button>
213→                        <img className="profile-media-lightbox-image" src={selectedMedia.url} alt={`${selectedMedia.bucket} media full size`} />
214→                    </div>
215→                </div>
216→                , profileParentContainer)}
217→
218→            {deleteCandidate &&
219→                profileParentContainer &&
220→                createPortal(
221→                <div className="profile-media-delete-confirm-overlay" onClick={handleCloseDeleteModal} role="presentation">
222→                    <div className="profile-media-delete-confirm-dialog" role="dialog" aria-modal="true" aria-label="Delete media image" onClick={(event) => event.stopPropagation()}>
223→                        <h3 className="profile-media-delete-confirm-title">Delete image?</h3>
224→                        <p className="profile-media-delete-confirm-copy">
225→                            This image will be deleted permanently. This action can&apos;t be undone.
226→                        </p>
227→                        {deleteMediaMutation.isError && <p className="profile-media-delete-confirm-error">Failed to delete image. Try again.</p>}
228→                        <div className="profile-media-delete-confirm-actions">
229→                            <button type="button" className="profile-media-delete-cancel-btn" onClick={handleCloseDeleteModal} disabled={deleteMediaMutation.isPending}>
230→                                Cancel
231→                            </button>
232→                            <button type="button" className="profile-media-delete-confirm-btn" onClick={handleConfirmDelete} disabled={deleteMediaMutation.isPending}>
233→                                {deleteMediaMutation.isPending ? "Deleting..." : "Delete"}
234→                            </button>
235→                        </div>
236→                    </div>
237→                </div>
238→                , profileParentContainer)}
239→        </section>
240→    );
241→};
