 11→const VisitedProfileMediaSection = () => {
 12→    const location = useLocation();
 13→    const stateData = location.state;
 14→    const queryUserId = new URLSearchParams(location.search).get("userId");
 15→    const visitedUserId = stateData?.userId || queryUserId;
 16→    const { session } = useAuth();
 17→
 18→    const [selectedMedia, setSelectedMedia] = useState(null);
 19→    const { ref: inViewRef, inView } = useInView({ threshold: 0.1 });
 20→
 21→    const { data, isLoading, isError, fetchNextPage, hasNextPage, isFetchingNextPage } = useInfiniteQuery({
 22→        queryKey: ["visitedProfileMedia", visitedUserId],
 23→        queryFn: ({ pageParam }) =>
 24→            getVisitedProfileMedia(session?.access_token, visitedUserId, pageParam, PROFILE_MEDIA_PAGE_SIZE),
 25→        initialPageParam: null,
 26→        getNextPageParam: (lastPage) => (lastPage?.hasMore ? lastPage?.nextCursor : undefined),
 27→        enabled: Boolean(visitedUserId && session?.access_token),
 28→        refetchOnWindowFocus: false,
 29→    });
 30→
 31→    const pages = data?.pages ?? [];
 32→    const mediaItems = pages.flatMap((page) => page?.data ?? []);
 33→    const unavailableBuckets = [...new Set(pages.flatMap((page) => page?.unavailableBuckets ?? []))];
 34→    const hasMedia = mediaItems.length > 0;
 35→
 36→    useEffect(() => {
 37→        if (inView && hasNextPage && !isFetchingNextPage) {
 38→            fetchNextPage();
 39→        }
 40→    }, [inView, hasNextPage, isFetchingNextPage, fetchNextPage]);
 41→
 42→    useEffect(() => {
 43→        if (!selectedMedia) return;
 44→
 45→        const handleEscape = (event) => {
 46→            if (event.key === "Escape") {
 47→                setSelectedMedia(null);
 48→            }
 49→        };
 50→
 51→        window.addEventListener("keydown", handleEscape);
 52→        return () => window.removeEventListener("keydown", handleEscape);
 53→    }, [selectedMedia]);
 54→
 55→    const profileParentContainer = typeof document !== "undefined" ? document.querySelector(".profile-parent-container") : null;
 56→
 57→    return (
 58→        <section className="profile-media-section" aria-label="Visited profile media">
 59→            <div className="profile-media-header-row">
 60→                <h2 className="profile-media-heading">
 61→                    Posts <span className="profile-media-count">({mediaItems.length})</span>
 62→                </h2>
 63→            </div>
 64→
 65→            {unavailableBuckets.length > 0 && <p className="profile-media-warning">Unable to list: {unavailableBuckets.join(", ")}.</p>}
 66→
 67→            {isLoading && (
 68→                <div className="profile-media-grid">
 69→                    {Array.from({ length: 9 }).map((_, index) => (
 70→                        <div key={`visited-media-loading-${index}`} className="profile-media-grid-item profile-media-grid-loading-item" />
 71→                    ))}
 72→                </div>
 73→            )}
 74→
 75→            {!isLoading && isError && <p className="profile-media-empty-state">Unable to load media right now.</p>}
 76→
 77→            {!isLoading && !isError && !hasMedia && <p className="profile-media-empty-state">No media found yet.</p>}
 78→
 79→            {!isLoading && !isError && hasMedia && (
 80→                <div className="profile-media-grid">
 81→                    {mediaItems.map((item) => (
 82→                        <div key={item.id} className="profile-media-grid-item">
 83→                            <button
 84→                                className="profile-media-grid-image-button"
 85→                                type="button"
 86→                                onClick={() => setSelectedMedia(item)}
 87→                                title={`View ${item.bucket} image full size`}
 88→                            >
 89→                                <img className="profile-media-image" src={item.url} alt={`${item.bucket} media`} loading="lazy" />
 90→                            </button>
 91→                        </div>
 92→                    ))}
 93→                    {isFetchingNextPage &&
 94→                        Array.from({ length: PROFILE_MEDIA_PAGE_SIZE }).map((_, index) => (
 95→                            <div key={`visited-media-loading-next-${index}`} className="profile-media-grid-item profile-media-grid-loading-item" />
 96→                        ))}
 97→                </div>
 98→            )}
 99→
100→            {!isLoading && hasMedia && hasNextPage && <div ref={inViewRef} className="profile-media-infinite-sentinel" />}
101→
102→            {selectedMedia &&
103→                profileParentContainer &&
104→                createPortal(
105→                    <div className="profile-media-lightbox-overlay" onClick={() => setSelectedMedia(null)} role="presentation">
106→                        <div
107→                            className="profile-media-lightbox-dialog"
108→                            role="dialog"
109→                            aria-modal="true"
110→                            aria-label="Full size media preview"
111→                            onClick={(event) => event.stopPropagation()}
112→                        >
113→                            <button
114→                                className="profile-media-lightbox-close"
115→                                type="button"
116→                                onClick={() => setSelectedMedia(null)}
117→                                aria-label="Close image preview"
118→                            >
119→                                <svg xmlns="http://www.w3.org/2000/svg" height="22" viewBox="0 -960 960 960" width="22" fill="currentColor">
120→                                    <path d="m291-240-51-51 189-189-189-189 51-51 189 189 189-189 51 51-189 189 189 189-51 51-189-189-189 189Z" />
121→                                </svg>
122→                            </button>
123→                            <img className="profile-media-lightbox-image" src={selectedMedia.url} alt={`${selectedMedia.bucket} media full size`} />
124→                        </div>
125→                    </div>,
126→                    profileParentContainer
127→                )}
128→        </section>
129→    );
130→};
131→
132→export default VisitedProfileMediaSection;
